const input = $('Workflow Trigger').first().json;
const action = input.action;
const tenantId = input.tenant_id;
const phone = input.phone;
const customerName = input.customer_name || '';
const customerId = input.customer_id || '';

const entries = $input.all().map((entry) => entry.json).filter((entry) => entry && entry.document);
const cartDocs = entries.map((raw) => {
  const fields = raw.document.fields || {};
  const items = [];
  if (fields.items?.arrayValue?.values) {
    for (const value of fields.items.arrayValue.values) {
      if (value.mapValue?.fields) {
        const itemFields = value.mapValue.fields;
        items.push({
          sku: itemFields.sku?.stringValue || '',
          product_name: itemFields.product_name?.stringValue || '',
          price: Number(itemFields.price?.doubleValue ?? itemFields.price?.integerValue ?? 0),
          quantity: Number(itemFields.quantity?.integerValue ?? itemFields.quantity?.doubleValue ?? 1),
        });
      }
    }
  }

  return {
    id: raw.document.name.split('/').pop(),
    updatedAt: fields.updated_at?.stringValue || fields.created_at?.stringValue || '',
    status: fields.status?.stringValue || 'open',
    items,
  };
}).sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));

const primaryCartId = cartDocs[0]?.id || null;
const duplicateCartIds = cartDocs.slice(1).map((doc) => doc.id);
const mergedBySku = new Map();
for (const doc of cartDocs) {
  for (const item of doc.items) {
    const sku = String(item.sku || '').trim();
    if (!sku) {
      continue;
    }

    const current = mergedBySku.get(sku);
    if (current) {
      current.quantity += Number(item.quantity || 0);
      if (!current.product_name && item.product_name) {
        current.product_name = item.product_name;
      }
      if (!current.price && item.price) {
        current.price = item.price;
      }
    } else {
      mergedBySku.set(sku, {
        sku,
        product_name: String(item.product_name || '').trim(),
        price: Number(item.price || 0),
        quantity: Number(item.quantity || 0),
      });
    }
  }
}

const cart = {
  items: Array.from(mergedBySku.values()).filter((item) => item.sku && item.quantity > 0),
  total: 0,
  status: cartDocs[0]?.status || 'open',
};

function calcTotal(items) {
  return Math.round(items.reduce((sum, item) => sum + (Number(item.price || 0) * Number(item.quantity || 0)), 0) * 100) / 100;
}

function makeOutput(actionToPersist, msg, items) {
  const finalItems = items || cart.items;
  const base = {
    success: true,
    items: finalItems,
    total: calcTotal(finalItems),
    item_count: finalItems.reduce((sum, item) => sum + Number(item.quantity || 0), 0),
    message: msg,
  };

  if (actionToPersist) {
    base._action = actionToPersist;
    base._primaryCartId = primaryCartId;
    base._duplicateCartIds = duplicateCartIds;
    base._tenantId = tenantId;
    base._phone = phone;
    base._customerName = customerName;
    base._customerId = customerId;
  }
  return [{ json: base }];
}

if (action === 'view') {
  if (cart.items.length === 0) {
    return [{ json: { success: true, empty: true, message: 'Carrinho vazio.', items: [], total: 0, item_count: 0 } }];
  }
  cart.total = calcTotal(cart.items);
  return [{ json: { success: true, empty: false, items: cart.items, total: cart.total, item_count: cart.items.reduce((sum, item) => sum + Number(item.quantity || 0), 0) } }];
}

if (action === 'clear') {
  if (!primaryCartId && duplicateCartIds.length === 0) {
    return [{ json: { success: true, message: 'Carrinho já estava vazio.', items: [], total: 0, item_count: 0 } }];
  }
  return makeOutput('delete', 'Carrinho limpo.', []);
}

if (action === 'add') {
  const sku = String(input.sku || '').trim();
  const qty = Number(input.quantity || 1);
  const newItem = {
    sku,
    product_name: String(input.product_name || '').trim(),
    price: Number(input.price || 0),
    quantity: qty,
  };

  const existingIndex = cart.items.findIndex((item) => item.sku === sku);
  if (existingIndex >= 0) {
    cart.items[existingIndex].quantity += newItem.quantity;
    if (!cart.items[existingIndex].product_name && newItem.product_name) {
      cart.items[existingIndex].product_name = newItem.product_name;
    }
    if (!cart.items[existingIndex].price && newItem.price) {
      cart.items[existingIndex].price = newItem.price;
    }
  } else {
    cart.items.push(newItem);
  }

  return makeOutput(primaryCartId ? 'update' : 'create', `${newItem.product_name} adicionado ao carrinho.`, cart.items);
}

if (action === 'remove') {
  const sku = String(input.sku || '').trim();
  const before = cart.items.length;
  cart.items = cart.items.filter((item) => item.sku !== sku);

  if (cart.items.length === before) {
    return [{ json: { success: false, message: 'Item não encontrado no carrinho.' } }];
  }

  if (cart.items.length === 0 && (primaryCartId || duplicateCartIds.length > 0)) {
    return makeOutput('delete', 'Item removido. Carrinho ficou vazio.', []);
  }
  return makeOutput(primaryCartId ? 'update' : 'create', 'Item removido.', cart.items);
}

if (action === 'update_qty') {
  const sku = String(input.sku || '').trim();
  const newQty = Number(input.quantity || 1);
  const item = cart.items.find((entry) => entry.sku === sku);

  if (!item) {
    return [{ json: { success: false, message: 'Item não encontrado no carrinho.' } }];
  }

  if (newQty <= 0) {
    cart.items = cart.items.filter((entry) => entry.sku !== sku);
  } else {
    item.quantity = newQty;
  }

  if (cart.items.length === 0 && (primaryCartId || duplicateCartIds.length > 0)) {
    return makeOutput('delete', 'Quantidade atualizada. Carrinho ficou vazio.', []);
  }
  return makeOutput(primaryCartId ? 'update' : 'create', 'Quantidade atualizada.', cart.items);
}

return [{ json: { success: false, message: 'Ação desconhecida: ' + action } }];

const data = $input.first().json;
const action = data._action;
const tenantId = data._tenantId;
const primaryCartId = data._primaryCartId || null;
const duplicateCartIds = Array.isArray(data._duplicateCartIds) ? data._duplicateCartIds.filter(Boolean) : [];
const baseUrl = `https://firestore.googleapis.com/v1/projects/saas-manu-project/databases/(default)/documents/tenants/${tenantId}`;
const allCartIds = Array.from(new Set([primaryCartId, ...duplicateCartIds].filter(Boolean)));

if (action === 'delete' && allCartIds.length > 0) {
  return allCartIds.map((cartId) => ({ json: { method: 'DELETE', url: `${baseUrl}/carts/${cartId}`, body: null } }));
}

const itemsArray = (data.items || []).map((item) => ({
  mapValue: {
    fields: {
      sku: { stringValue: item.sku || '' },
      product_name: { stringValue: item.product_name || '' },
      price: { doubleValue: Number(item.price || 0) },
      quantity: { integerValue: String(item.quantity || 0) },
    }
  }
}));

const body = {
  fields: {
    phone: { stringValue: data._phone || '' },
    customer_name: { stringValue: data._customerName || '' },
    customer_id: { stringValue: data._customerId || '' },
    items: { arrayValue: { values: itemsArray } },
    total: { doubleValue: Number(data.total || 0) },
    status: { stringValue: 'open' },
    updated_at: { stringValue: new Date().toISOString() }
  }
};

const requests = [];
if (action === 'create') {
  body.fields.created_at = { stringValue: new Date().toISOString() };
  requests.push({ method: 'POST', url: `${baseUrl}/carts`, body });
} else if (action === 'update' && primaryCartId) {
  const mask = 'updateMask.fieldPaths=items&updateMask.fieldPaths=total&updateMask.fieldPaths=status&updateMask.fieldPaths=updated_at';
  requests.push({ method: 'PATCH', url: `${baseUrl}/carts/${primaryCartId}?${mask}`, body });
}

for (const cartId of duplicateCartIds) {
  requests.push({ method: 'DELETE', url: `${baseUrl}/carts/${cartId}`, body: null });
}

if (requests.length === 0) {
  return [{ json: { method: 'NONE' } }];
}

return requests.map((request) => ({ json: request }));

const prev = $('Lógica do Carrinho').first().json;
const { _action, _cartId, _primaryCartId, _duplicateCartIds, _tenantId, _phone, _customerName, _customerId, ...clean } = prev;
return [{ json: clean }];
